from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson.json_util import dumps, ObjectId

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client['cmsdb']
user_profiles = db['user_profiles']

@app.route('/profile', methods=['POST'])
def create_profile():
    data = request.json
    user_profiles.insert_one(data)
    return jsonify({'msg': 'Profile created successfully!'})

@app.route('/profile/<string:user_id>', methods=['GET'])
def get_profile(user_id):
    profile = user_profiles.find_one({'_id': ObjectId(user_id)})
    if profile:
        return dumps(profile)
    return jsonify({'msg': 'Profile not found'}), 404

@app.route('/profile/query', methods=['GET'])
def query_profiles():
    query = request.args.to_dict()
    profiles = user_profiles.find(query)
    return dumps(profiles)

@app.route('/profile/aggregate', methods=['GET'])
def aggregate_profiles():
    pipeline = [
        {"$group": {"_id": "$status", "count": {"$sum": 1}}},
        {"$sort": {"count": -1}}
    ]
    results = user_profiles.aggregate(pipeline)
    return dumps(results)

if __name__ == '__main__':
    app.run(debug=True)